script:
frappe.ui.form.on('Daily Attendance Report', {
    refresh: function(frm) {
    }
});

frappe.ui.form.on('Employee Attendance Detail', {
    checkin_time: function(frm, cdt, cdn) {
        calculate_worked_hours(frm, cdt, cdn);
    },
    checkout_time: function(frm, cdt, cdn) {
        calculate_worked_hours(frm, cdt, cdn);
    }
});

function calculate_worked_hours(frm, cdt, cdn) {
    let row = frappe.get_doc(cdt, cdn);
    
    if (row.checkin_time && row.checkout_time) {
        let in_time = new Date(row.checkin_time);
        let out_time = new Date(row.checkout_time);
        
        if (out_time > in_time) {
            let diff_ms = out_time - in_time;
            let hours = diff_ms / (1000 * 60 * 60);
            
            frappe.model.set_value(cdt, cdn, 'worked_hours', hours.toFixed(2));
        } else {
            frappe.model.set_value(cdt, cdn, 'worked_hours', 0);
        }
    } else {
        frappe.model.set_value(cdt, cdn, 'worked_hours', 0);
    }
}
